import json
import sys

def two_sum(nums, target):
    seen = {}
    for i, n in enumerate(nums):
        if target - n in seen:
            return [seen[target-n], i]
        seen[n] = i

if __name__ == '__main__':
    data = json.loads(sys.stdin.read())
    result = two_sum(data['nums'], data['target'])
    print(json.dumps(result))
